"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[5353],{9433(t,e,r){r.r(e),r.d(e,{comp:()=>o,data:()=>n});var a=r(641);const d={},o=(0,r(6262).A)(d,[["render",function(t,e){return(0,a.uX)(),(0,a.CE)("div",null,[...e[0]||(e[0]=[(0,a.Fv)('<h1 id="admin-overview" tabindex="-1"><a class="header-anchor" href="#admin-overview"><span>Admin Overview</span></a></h1><p>The plugin adds 15 admin pages, all under <strong>WooCommerce → Webkul Addons → Auctions</strong>. This page maps each one to what you&#39;d open it for.</p><p><img src="/auctions-for-woocommerce/images/screenshots/admin-dashboard.png" alt="Auctions admin home — the Auction Intelligence dashboard with KPIs, bid trend, status donut, leaderboards and the live activity feed"></p><h2 id="at-a-glance" tabindex="-1"><a class="header-anchor" href="#at-a-glance"><span>At a glance</span></a></h2><table><thead><tr><th>Page</th><th>Slug</th><th>Open it for</th></tr></thead><tbody><tr><td><a href="/admin-dashboard.html" target="_blank" rel="noopener noreferrer">Dashboard</a></td><td><code>wkafw-dashboard</code></td><td>KPI overview, charts, activity feed</td></tr><tr><td><a href="/admin-auctions.html" target="_blank" rel="noopener noreferrer">All Auctions</a></td><td><code>wkafw-auctions</code></td><td>List, filter, bulk-act on auctions</td></tr><tr><td><a href="/admin-add-auction.html" target="_blank" rel="noopener noreferrer">Add / Edit Auction</a></td><td><code>wkafw-add-auction</code></td><td>Create a single auction</td></tr><tr><td><a href="/admin-bids.html" target="_blank" rel="noopener noreferrer">Bids</a></td><td><code>wkafw-bids</code></td><td>Inspect, retract, delete bids</td></tr><tr><td><a href="/admin-reports.html" target="_blank" rel="noopener noreferrer">Reports</a></td><td><code>wkafw-reports</code></td><td>Revenue / bidder / category reports</td></tr><tr><td><a href="/admin-events.html" target="_blank" rel="noopener noreferrer">Events</a></td><td><code>wkafw-events</code></td><td>Multi-lot auction events</td></tr><tr><td><a href="/admin-wallet.html" target="_blank" rel="noopener noreferrer">Wallet</a></td><td><code>wkafw-wallet</code></td><td>Top-up, debit, refund customer wallets</td></tr><tr><td><a href="/admin-disputes.html" target="_blank" rel="noopener noreferrer">Disputes</a></td><td><code>wkafw-disputes</code></td><td>Open / resolve buyer disputes</td></tr><tr><td><a href="/admin-users.html" target="_blank" rel="noopener noreferrer">Blocked Users</a></td><td><code>wkafw-users</code></td><td>Ban list</td></tr><tr><td><a href="/admin-fraud.html" target="_blank" rel="noopener noreferrer">Fraud Detection</a></td><td><code>wkafw-fraud</code></td><td>Velocity / IP / risk rules</td></tr><tr><td><a href="/admin-tools.html" target="_blank" rel="noopener noreferrer">Tools</a></td><td><code>wkafw-tools</code></td><td>CSV import / export / mappings</td></tr><tr><td><a href="/admin-settings.html" target="_blank" rel="noopener noreferrer">Settings</a></td><td><code>wkafw-settings</code></td><td>All 132 plugin options</td></tr><tr><td><a href="/admin-design-studio.html" target="_blank" rel="noopener noreferrer">Design Studio</a></td><td><code>wkafw-design</code></td><td>Live brand preview</td></tr><tr><td><a href="/admin-pending-review.html" target="_blank" rel="noopener noreferrer">Pending Review</a></td><td><code>wkafw-pending-review</code></td><td>Vendor lot moderation</td></tr><tr><td><a href="/admin-audit-log.html" target="_blank" rel="noopener noreferrer">Audit Log</a></td><td><code>wkafw-audit-log</code></td><td>Hash-chain bid trail</td></tr></tbody></table><h2 id="capability" tabindex="-1"><a class="header-anchor" href="#capability"><span>Capability</span></a></h2><p>All pages require the <strong><code>manage_woocommerce</code></strong> capability — by default, <strong>shop manager</strong> and above. To grant access to other roles, use a capability plugin or <code>add_cap()</code> in <code>functions.php</code>.</p><h2 id="common-patterns" tabindex="-1"><a class="header-anchor" href="#common-patterns"><span>Common patterns</span></a></h2><p>Each admin page follows the same convention:</p><ul><li><strong>Top hero</strong> — page title + filters / range pickers</li><li><strong>KPI / summary row</strong> — high-level numbers</li><li><strong>Main content</strong> — list table, form, or chart grid</li><li><strong>Bulk actions</strong> — drop-down + selection checkboxes (where applicable)</li></ul><p>Filters in the URL persist on page reload (e.g., <code>?status=active&amp;range=30</code>). Bookmark a filtered view to revisit it.</p><h2 id="bulk-actions-cheat-sheet" tabindex="-1"><a class="header-anchor" href="#bulk-actions-cheat-sheet"><span>Bulk actions cheat sheet</span></a></h2><table><thead><tr><th>Page</th><th>Bulk actions available</th></tr></thead><tbody><tr><td>All Auctions</td><td>Start, Pause, End, Extend, Cancel, Delete, Duplicate</td></tr><tr><td>Bids</td><td>Delete, Mark fraudulent</td></tr><tr><td>Disputes</td><td>Resolve, Close</td></tr><tr><td>Blocked Users</td><td>Unblock</td></tr><tr><td>Pending Review</td><td>Approve, Reject</td></tr></tbody></table><h2 id="csv-exports" tabindex="-1"><a class="header-anchor" href="#csv-exports"><span>CSV exports</span></a></h2><p>These pages stream CSVs:</p><table><thead><tr><th>Page</th><th>Export</th></tr></thead><tbody><tr><td><a href="/admin-reports.html" target="_blank" rel="noopener noreferrer">Reports</a></td><td>Revenue, bidders, by category</td></tr><tr><td><a href="/admin-disputes.html" target="_blank" rel="noopener noreferrer">Disputes</a></td><td>Open / resolved disputes</td></tr><tr><td><a href="/admin-tools.html" target="_blank" rel="noopener noreferrer">Tools</a></td><td>Auctions, bids, watchers, full data</td></tr><tr><td><a href="/admin-audit-log.html" target="_blank" rel="noopener noreferrer">Audit Log</a></td><td>Hash-chain ledger</td></tr></tbody></table><p>Big exports (&gt;500 rows) run via Action Scheduler in the background; you&#39;ll get an email or a polling notice when ready.</p><h2 id="where-data-shows-up" tabindex="-1"><a class="header-anchor" href="#where-data-shows-up"><span>Where data shows up</span></a></h2><table><thead><tr><th>Data</th><th>Where you see it</th></tr></thead><tbody><tr><td>Auctions</td><td>All Auctions, Dashboard</td></tr><tr><td>Bids</td><td>Bids, Audit Log, Dashboard</td></tr><tr><td>Watchlist</td><td>Reports, Dashboard</td></tr><tr><td>Disputes</td><td>Disputes</td></tr><tr><td>Events / lots / registrations</td><td>Events</td></tr><tr><td>Audit log</td><td>Dashboard activity, Audit Log</td></tr><tr><td>Wallet ledger</td><td>Wallet</td></tr><tr><td>Vendor commissions</td><td>Reports, multi-vendor reporting</td></tr></tbody></table><h2 id="next" tabindex="-1"><a class="header-anchor" href="#next"><span>Next</span></a></h2><ul><li><a href="/admin-dashboard.html" target="_blank" rel="noopener noreferrer">Dashboard →</a> — open it now</li><li><a href="/admin-settings.html" target="_blank" rel="noopener noreferrer">Settings →</a> — configure once, ship many</li></ul>',21)])])}]]),n=JSON.parse('{"path":"/admin-overview.html","title":"Admin Overview","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"At a glance","slug":"at-a-glance","link":"#at-a-glance","children":[]},{"level":2,"title":"Capability","slug":"capability","link":"#capability","children":[]},{"level":2,"title":"Common patterns","slug":"common-patterns","link":"#common-patterns","children":[]},{"level":2,"title":"Bulk actions cheat sheet","slug":"bulk-actions-cheat-sheet","link":"#bulk-actions-cheat-sheet","children":[]},{"level":2,"title":"CSV exports","slug":"csv-exports","link":"#csv-exports","children":[]},{"level":2,"title":"Where data shows up","slug":"where-data-shows-up","link":"#where-data-shows-up","children":[]},{"level":2,"title":"Next","slug":"next","link":"#next","children":[]}],"git":{},"filePathRelative":"admin-overview.md"}')}}]);